parameters.functionCode:
const sensors = $input.item.json;
const soilZones = sensors.soil_moisture;
const temperature = sensors.temperature_humidity.temperature;
const humidity = sensors.temperature_humidity.humidity;

let zonesNeedingWater = [];

// Her zone'u kontrol et
soilZones.forEach(zone => {
  let needsWater = false;
  let duration = 60000; // Varsayılan 60 saniye
  let reason = '';

  // Toprak nem seviyesi
  if (zone.moisture < 20) {
    needsWater = true;
    duration = 90000; // 90 saniye (çok kuru)
    reason = 'Çok kuru';
  } else if (zone.moisture < 30) {
    needsWater = true;
    duration = 60000; // 60 saniye
    reason = 'Kuru';
  }

  // Hava koşulları kontrolü
  if (needsWater) {
    // Çok sıcaksa sulama süresini artır
    if (temperature > 30) {
      duration = Math.round(duration * 1.3);
      reason += ', Sıcak hava';
    }

    // Nem yüksekse sulama süresini azalt
    if (humidity > 70) {
      duration = Math.round(duration * 0.8);
      reason += ', Yüksek nem';
    }

    // Gece vakti mi?
    const hour = new Date().getHours();
    const isNight = (hour < 6 || hour > 20);

    if (isNight) {
      // Gece sulamayı ertele (sabah 6'ya kadar bekle)
      needsWater = false;
      reason = 'Gece sulama ertelendi';
    }

    if (needsWater) {
      zonesNeedingWater.push({
        zone: zone.zone,
        name: zone.name,
        moisture: zone.moisture,
        duration: duration,
        reason: reason
      });
    }
  }
});

return {
  json: {
    zonesNeedingWater: zonesNeedingWater,
    hasZonesNeedingWater: zonesNeedingWater.length > 0,
    temperature: temperature,
    humidity: humidity,
    timestamp: new Date()
  }
};

const zone = $input.item.json.zonesNeedingWater[$node['Zone\'ları Ayır'].index];

return {
  json: {
    action: 'start',
    zone: zone.zone,
    duration: zone.duration,
    reason: zone.reason
  }
};

